public sealed class AppConfig {
  private static readonly Lazy<AppConfig> _instance = new Lazy<AppConfig>(() => new AppConfig());
  public static AppConfig Instance => _instance.Value;

  public string EnvironmentName { get; set; } = "dev";

  private AppConfig() { }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Instance_ReturnsSameReference() {
  var first = AppConfig.Instance;
  var second = AppConfig.Instance;
  Assert.AreSame(first, second);
}

[TestMethod]
public void Instance_SharesStateAcrossCalls() {
  AppConfig.Instance.EnvironmentName = "prod";
  Assert.AreEqual("prod", AppConfig.Instance.EnvironmentName);
}
